use strict;
use warnings;
use PDF::API2;
use Text::Unidecode;

# Function to extract text from a PDF
sub extract_text {
    my ($pdf) = @_;
    my $text = '';

    for my $page (1..$pdf->pages) {
        my $textpage = $pdf->page($page)->text;
        $text .= $textpage;
    }
    return $text;
}

# Function to extract metadata from a PDF
sub extract_metadata {
    my ($pdf) = @_;
    my %metadata = $pdf->info;

    return \%metadata;
}

# Main script
my $pdf_file = 'example.pdf';  # Replace with your PDF file path

# Open the PDF file
my $pdf = PDF::API2->open($pdf_file);

# Extract text
my $text = extract_text($pdf);
print "Extracted Text:\n$text\n";

# Extract metadata
my $metadata = extract_metadata($pdf);
print "Metadata:\n";
foreach my $key (sort keys %$metadata) {
    print "$key: $metadata->{$key}\n";
}

# Close the PDF file
$pdf->close();
